import base64
from pathlib import Path

def load_image_b64(path: str, media_type: str = "image/png") -> dict:
    """Return an Anthropic-style image block for a local file."""
    data = base64.standard_b64encode(Path(path).read_bytes()).decode()
    return {
        "type": "image",
        "source": {
            "type": "base64",
            "media_type": media_type,
            "data": data,
        },
    }

def build_few_shot_messages(examples: list[dict], live_image_path: str) -> list[dict]:
    """
    examples: list of {"image_path": str, "media_type": str, "output": str}
    Returns a messages list ready for the Anthropic client.
    """
    messages = []
    instruction = (
        "Extract the vendor name, total amount, and currency from this receipt. "
        "Return ONLY a JSON object with keys: vendor, total, currency. "
        "Do not include any explanation."
    )
    for ex in examples:
        messages.append({
            "role": "user",
            "content": [
                load_image_b64(ex["image_path"], ex.get("media_type", "image/png")),
                {"type": "text", "text": instruction},
            ],
        })
        messages.append({
            "role": "assistant",
            "content": ex["output"],
        })
    # Live query — no assistant turn
    messages.append({
        "role": "user",
        "content": [
            load_image_b64(live_image_path),
            {"type": "text", "text": instruction},
        ],
    })
    return messages

import anthropic, base64, json
from pathlib import Path

# Simulated database of annotated examples
EXAMPLE_DB = {
    "supplier_acme": [
        {"path": "examples/acme_inv_2024_11.png",
         "output": '{"vendor":"Acme Corp","invoice_no":"INV-9981","total":3420.00,"currency":"USD","due":"2024-12-15"}'},
        {"path": "examples/acme_inv_2024_10.png",
         "output": '{"vendor":"Acme Corp","invoice_no":"INV-9901","total":2890.00,"currency":"USD","due":"2024-11-20"}'},
    ],
}
FALLBACK_EXAMPLES = [
    {"path": "examples/generic_goods_1.png",
     "output": '{"vendor":"Generic Supplier","invoice_no":"G-001","total":500.00,"currency":"USD","due":"2025-01-01"}'},
]

client = anthropic.Anthropic()

def extract_invoice(image_path: str, supplier_id: str | None = None) -> dict:
    examples = EXAMPLE_DB.get(supplier_id, FALLBACK_EXAMPLES)
    instruction = (
        "Extract invoice fields. Return JSON with keys: "
        "vendor, invoice_no, total (float), currency (ISO 4217), due (YYYY-MM-DD)."
    )
    messages = []
    for ex in examples:
        data = base64.standard_b64encode(Path(ex["path"]).read_bytes()).decode()
        messages.append({
            "role": "user",
            "content": [
                {"type": "image", "source": {"type": "base64",
                 "media_type": "image/png", "data": data}},
                {"type": "text", "text": instruction},
            ],
        })
        messages.append({"role": "assistant", "content": ex["output"]})
    live_data = base64.standard_b64encode(Path(image_path).read_bytes()).decode()
    messages.append({
        "role": "user",
        "content": [
            {"type": "image", "source": {"type": "base64",
             "media_type": "image/png", "data": live_data}},
            {"type": "text", "text": instruction},
        ],
    })
    resp = client.messages.create(model="claude-opus-4-5", max_tokens=256, messages=messages)
    return json.loads(resp.content[0].text)

