import re

def safe_parse(text: str) -> dict | None:
    # Strip any preamble before the JSON object
    match = re.search(r'\{.*\}', text, re.DOTALL)
    if not match:
        return None
    try:
        return json.loads(match.group())
    except json.JSONDecodeError:
        return None
